import { useState, useEffect, useMemo, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useNavigate } from "react-router-dom";
import {
  LayoutDashboard,
  ShoppingCart,
  Users,
  Package,
  BarChart3,
  Settings,
  User,
  LogOut,
} from "lucide-react";

import { adminDashboardDesign as design } from "../../design/adminDashboardDesign";

const menuItems = [
  { name: "Dashboard", icon: LayoutDashboard },
  { name: "Products", icon: Package },
  { name: "Orders", icon: ShoppingCart },
  { name: "Users", icon: Users },
  { name: "Analytics", icon: BarChart3 },
  { name: "Settings", icon: Settings },
];

const AdminDashboard = () => {
  const navigate = useNavigate();
  const adminInfo = JSON.parse(localStorage.getItem("adminInfo"));

  const [search, setSearch] = useState("");
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const dropdownRef = useRef(null);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setDropdownOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () =>
      document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const getInitials = (name) => {
    if (!name) return "";
    const words = name.trim().split(" ");
    if (words.length === 1) return words[0][0].toUpperCase();
    return (
      words[0][0].toUpperCase() +
      (words[1] ? words[1][0].toUpperCase() : "")
    );
  };

  const filteredMenu = useMemo(() => {
    return menuItems.filter((item) =>
      item.name.toLowerCase().includes(search.toLowerCase())
    );
  }, [search]);

  const handleLogout = () => {
    localStorage.removeItem("adminInfo");
    localStorage.removeItem("token");
    navigate("/admin/login");
  };

  return (
    <div className={design.layout.wrapper}>
      {/* NAVBAR */}
      <div className={design.layout.navbar}>
        <button
          onClick={() => setSidebarOpen(true)}
          className={design.navbar.menuButton}
        >
          ☰
        </button>

        <input
          type="text"
          placeholder="Search menu..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className={design.colors.input}
        />

        {/* Avatar */}
        <div className={design.navbar.avatarWrapper} ref={dropdownRef}>
          <div
            onClick={() => setDropdownOpen(!dropdownOpen)}
            className={design.navbar.avatar}
          >
            {getInitials(adminInfo?.name)}
          </div>

          <AnimatePresence>
            {dropdownOpen && (
              <motion.div
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: 10 }}
                className={design.dropdown.wrapper}
              >
                <div className={design.dropdown.header}>
                  <p>{adminInfo?.name}</p>
                  <span>{adminInfo?.email}</span>
                </div>

                <div
                  onClick={() => navigate("/admin/profile")}
                  className={design.dropdown.item}
                >
                  <User size={16} />
                  Profile
                </div>

                <div
                  onClick={handleLogout}
                  className={design.dropdown.logout}
                >
                  <LogOut size={16} />
                  Logout
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>

      {/* BODY */}
      <div className={design.layout.body}>
        <AnimatePresence>
          {sidebarOpen && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setSidebarOpen(false)}
              className={design.colors.overlay}
            />
          )}
        </AnimatePresence>

        <motion.aside
          initial={false}
          animate={{ x: sidebarOpen ? 0 : -300 }}
          transition={{ duration: 0.3 }}
          className={design.layout.sidebar}
        >
          <div className={design.sidebar.header}>
            <div>
              <h2>Admin Panel</h2>
              <p>Nahid Enterprise</p>
            </div>

            <button
              onClick={() => setSidebarOpen(false)}
              className={design.sidebar.closeButton}
            >
              ✕
            </button>
          </div>

          <nav className={design.sidebar.nav}>
            {filteredMenu.map((item, index) => {
              const Icon = item.icon;
              return (
                <div key={index} className={design.sidebar.navItem}>
                  <Icon size={18} />
                  {item.name}
                </div>
              );
            })}
          </nav>
        </motion.aside>

        <div className={design.layout.content}>
          <h2>Welcome Back 👋</h2>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
